import matplotlib.pyplot as pltimport tensorflow as tfimport pandas as pd# 导入波士顿房价数据集boston_housing = tf.keras.datasets.boston_housing(train_x, train_y), (test_x, test_y) = boston_housing.load_data()print(test_x.shape)column_names = ['CRIM', 'ZN', 'INDUS', 'CHAS', 'NOX', 'RM', 'AGE', 'DIS', 'RAD',                'TAX', 'PTRATIO', 'B', 'LSTAT']df = pd.DataFrame(test_x, columns=column_names)print(df.head())# 特征数据归一化def normalize(data_nz):    # 对特征数据{0到12}列 做（0-1）归一化    return (data_nz - data_nz.min(axis=0)) \           / (data_nz.max(axis=0) - data_nz.min(axis=0))# 数据归一化处理train_x = normalize(train_x)test_x = normalize(test_x)Y_train = tf.constant(train_y.reshape(-1, 1), tf.float32)Y_test = tf.constant(test_y.reshape(-1, 1), tf.float32)print('train_y.shape:', train_y.shape, 'Y_train.shape:', Y_train.shape)print('test_y.shape:', test_y.shape, 'Y_test.shape:', Y_test.shape)# 定义模型class Model(object):    def __init__(self):        self.w = tf.Variable(tf.random.normal([13, 1], stddev=0.01),                             dtype=tf.float32)        self.b = tf.Variable(1.2)    def __call__(self, inputs):        return inputs @ self.w + self.b# 定义损失函数def compute_loss(y_true, y_pred):    return tf.reduce_mean(tf.square(y_true-y_pred))# 训练模型mse_train = []      # 用来保存训练集每次训练后的损失值mse_test = []       # 用来保存测试集每次训练后的损失值learn_rate = 0.008   # 学习率epoch = 3000        # 训练轮数model = Model()for i in range(0, epoch + 1):    with tf.GradientTape() as tape:        PRED_train = model(train_x)        Loss_train = 0.5 * compute_loss(Y_train, PRED_train)        PRED_test = model(test_x)        Loss_test = 0.5 * compute_loss(Y_test, PRED_test)    grad = tape.gradient(Loss_train, [model.w, model.b])    model.w.assign_sub(learn_rate * grad[0])    model.b.assign_sub(learn_rate * grad[1])    if i % 200 == 0:        print("epoch:%i, Train Loss:%f, Test Loss:%f" % (i, Loss_train, Loss_test))    mse_train.append(Loss_train)    mse_test.append(Loss_test)# 数据可视化plt.figure(figsize=(20, 4))plt.subplot(131)  # 绘制损失函数plt.ylabel("MSE")plt.plot(mse_train, color='blue', linewidth=2, label='train loss')plt.plot(mse_test, color='red', linewidth=2, label='test loss')plt.legend(loc='upper right')plt.subplot(132)  # 绘制训练集和预测结果的对比plt.plot(train_y, color='blue', marker='o', label='true_price')plt.plot(PRED_train, color='red', marker='.', label='predict')plt.legend()plt.ylabel('Price')plt.subplot(133)  # 绘制测试集和预测结果的对比plt.plot(test_y, color='blue', marker='o', label='true_price')plt.plot(PRED_test, color='red', marker='.', label='predict')plt.legend()plt.ylabel('Price')plt.show()